import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState({
    totalQueries: 0,
    avgResponseTime: 0,
    totalTime: 0
  });
  const [responseTime, setResponseTime] = useState(0);
  const [displayedAnswer, setDisplayedAnswer] = useState("");
  const [displayedStats, setDisplayedStats] = useState({
    totalQueries: 0,
    avgResponseTime: 0,
    lastResponse: 0
  });
  const [clock, setClock] = useState("--:--:--");

  useEffect(() => {
    const updateClock = () => {
      const now = new Date();
      const hh = String(now.getHours()).padStart(2, "0");
      const mm = String(now.getMinutes()).padStart(2, "0");
      const ss = String(now.getSeconds()).padStart(2, "0");
      setClock(`${hh}:${mm}:${ss}`);
    };

    updateClock();
    const clockId = setInterval(updateClock, 1000);
    return () => clearInterval(clockId);
  }, []);

  useEffect(() => {
    const start = {
      totalQueries: displayedStats.totalQueries,
      avgResponseTime: displayedStats.avgResponseTime,
      lastResponse: displayedStats.lastResponse
    };
    const target = {
      totalQueries: stats.totalQueries,
      avgResponseTime: stats.avgResponseTime,
      lastResponse: responseTime
    };

    const duration = 500;
    const startTime = performance.now();

    const step = (time) => {
      const progress = Math.min((time - startTime) / duration, 1);
      const lerp = (a, b) => a + (b - a) * progress;
      setDisplayedStats({
        totalQueries: Math.round(lerp(start.totalQueries, target.totalQueries)),
        avgResponseTime: Math.round(lerp(start.avgResponseTime, target.avgResponseTime)),
        lastResponse: Math.round(lerp(start.lastResponse, target.lastResponse))
      });
      if (progress < 1) {
        requestAnimationFrame(step);
      }
    };

    requestAnimationFrame(step);
  }, [stats, responseTime]);

  useEffect(() => {
    if (!answer) {
      setDisplayedAnswer("");
      return;
    }

    let index = 0;
    setDisplayedAnswer("");

    const intervalId = setInterval(() => {
      index += 2;
      setDisplayedAnswer(answer.slice(0, index));
      if (index >= answer.length) {
        clearInterval(intervalId);
      }
    }, 12);

    return () => clearInterval(intervalId);
  }, [answer]);

  const askQuestion = async () => {

    if (!question) return;

    setLoading(true);
    const startTime = Date.now();

    try {

      const response = await axios.post(
        "http://127.0.0.1:5000/ask",
        { question: question }
      );

      const endTime = Date.now();
      const time = endTime - startTime;
      setResponseTime(time);

      setAnswer(response.data.answer);

      // Update stats
      setStats(prev => ({
        totalQueries: prev.totalQueries + 1,
        totalTime: prev.totalTime + time,
        avgResponseTime: (prev.totalTime + time) / (prev.totalQueries + 1)
      }));

      setQuestion("");

    } catch (error) {

      setAnswer("Error connecting to backend.");

    }

    setLoading(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && e.ctrlKey) {
      askQuestion();
    }
  };

  return (
    <div className="app-wrapper">
      <div className="container">

        <div className="status-strip reveal-0">
          <div className="status-pill">
            <span className="status-dot"></span>
            System Online
          </div>
          <div className="status-pill">
            <span className="status-dot slow"></span>
            Model: Ready
          </div>
          <div className="status-pill">
            <span className={`status-dot ${loading ? "busy" : ""}`}></span>
            {loading ? "Processing" : "Idle"}
          </div>
          <div className="status-pill">
            <span className="status-dot slow"></span>
            {clock}
          </div>
        </div>

        <div className="header reveal-1">
          <div className="logo-section">
            <div className="logo">📡</div>
            <div>
              <div className="title" data-text="RAN Assistant Pro">RAN Assistant Pro</div>
              <div className="subtitle">
                Intelligent Telecom RAN Support System
              </div>
            </div>
          </div>
        </div>

        <div className="stats-dashboard reveal-2">
          <div className="stat-card">
            <div className="stat-label">Total Queries</div>
            <div className="stat-value">{displayedStats.totalQueries}</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Avg Response Time</div>
            <div className="stat-value">{displayedStats.avgResponseTime}ms</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Last Response</div>
            <div className="stat-value">{displayedStats.lastResponse}ms</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Model</div>
            <div className="stat-value model-name">llama-3.3-70b</div>
          </div>
        </div>

        <div className="input-section reveal-3">
          <label className="input-label">Ask Your Question</label>
          <textarea
            rows="5"
            placeholder="Ask telecom questions like:
• What is 5G RAN?
• Explain network slicing
• How does network densification support 5G?
(Press Ctrl+Enter to submit)"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            onKeyPress={handleKeyPress}
            className="input-textarea"
          />

          <div className="button-group">
            <button 
              onClick={askQuestion}
              disabled={loading || !question.trim()}
              className="btn-primary"
            >
              {loading ? "⏳ Generating..." : "🤖 Ask AI"}
            </button>
            <button 
              onClick={() => { setQuestion(""); setAnswer(""); }}
              className="btn-secondary"
            >
              Clear
            </button>
          </div>
        </div>

        {loading && (
          <div className="loading-container reveal-4">
            <div className="spinner"></div>
            <div className="loading-text">Generating Answer...</div>
          </div>
        )}

        {answer && !loading && (
          <div className="answer-section reveal-4">
            <div className="answer-header">
              <span className="answer-icon">✨</span>
              <span>AI Response</span>
              <span className="response-time">Response Time: {responseTime}ms</span>
            </div>
            <div className="answer-box">
              {displayedAnswer}
              {displayedAnswer.length < answer.length && (
                <span className="typing-caret">|</span>
              )}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

export default App;
